// Plain text / markdown - direct processing
const item = $input.first().json;
console.log(`[SUB_PARSE] Text/Markdown parsing: ${item.fileName}`);

// For text/markdown, content is already accessible
// In production, download the file and parse heading structure
const text = item.textContent || `Content of ${item.fileName}`;

// Extract sections from markdown headings
const sectionMatches = [];
const headingRegex = /^(#{1,3})\s+(.+)$/gm;
let match;
let secId = 0;
while ((match = headingRegex.exec(text)) !== null) {
  sectionMatches.push({
    id: `sec_${String(++secId).padStart(2,'0')}`,
    title: match[2].trim(),
    level: match[1].length,
    content: ''
  });
}

return [{
  json: {
    fileId: item.sampleId || item.fileId,
    fileName: item.fileName,
    fileType: item.fileType,
    plainText: text,
    sections: sectionMatches,
    metadata: {
      pageCount: Math.ceil(text.length / 3000),
      wordCount: text.split(/\s+/).filter(Boolean).length,
      hasTables: text.includes('|'),
      extractionMethod: 'text_parser'
    }
  }
}];
